import{c as t,Q as a,j as r,m as o}from"./chunks/framework.BXc4yaFE.js";const m=JSON.parse('{"title":"TLDR AI — 2026-05-16","description":"","frontmatter":{"title":"TLDR AI — 2026-05-16","date":"2026-05-16T00:00:00.000Z","source":"TLDR AI","type":"ai-news"},"headers":[],"relativePath":"research/ai-news/2026-05/2026-05-16-tldr-ai.md","filePath":"research/ai-news/2026-05/2026-05-16-tldr-ai.md","lastUpdated":1779894392000}'),n={name:"research/ai-news/2026-05/2026-05-16-tldr-ai.md"};function s(i,e,l,c,d,h){return a(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="⚡-tldr-ai-—-2026-05-16" tabindex="-1">⚡ TLDR AI — 2026-05-16 <a class="header-anchor" href="#⚡-tldr-ai-—-2026-05-16" aria-label="Permalink to &quot;⚡ TLDR AI — 2026-05-16&quot;">​</a></h1><blockquote><p>5 分鐘科技簡報，AI + 程式 + 產品精華濃縮 來源：<a href="https://tldr.tech/api/rss/ai" target="_blank" rel="noreferrer">TLDR AI</a></p></blockquote><hr><h2 id="grok-build-👨‍💻-codex-customizations-🤖-xai-exodus-👋" tabindex="-1"><a href="https://tldr.tech/ai/2026-05-15" target="_blank" rel="noreferrer">Grok Build 👨‍💻 , Codex customizations 🤖, xAI exodus 👋</a> <a class="header-anchor" href="#grok-build-👨‍💻-codex-customizations-🤖-xai-exodus-👋" aria-label="Permalink to &quot;[Grok Build 👨‍💻 , Codex customizations 🤖, xAI exodus 👋](https://tldr.tech/ai/2026-05-15)&quot;">​</a></h2><p><em>⚡ TLDR AI | 2026-05-15</em></p><p><strong><a href="https://x.ai/news/grok-build-cli?utm_source=tldrai" target="_blank" rel="noreferrer">Introducing Grok Build (2 minute read)</a></strong> Grok Build is a coding agent that runs from the terminal. It is now in early beta for SuperGrok Heavy subscribers. AGENTS.md, plugin, hooks, skills, and MCP servers all work out of the box. Grok Build supports subagents for larger tasks, and it also supports deep worktree integrations, so users can launch subagents in their own worktrees. There is a headless mode that allows the easy running of agents inside scripts and automations. <strong><a href="https://cursor.com/blog/cloud-agent-development-environments?utm_source=tldrai" target="_blank" rel="noreferrer">Cloud Agent Development Environments (6 minute read)</a></strong> Cursor detailed a new system for configuring cloud-based development environments tailored to autonomous coding agents. It supports multi-repo, environment configuration as code, automated setup workflows, and governance controls for managing fleets of parallel agents. <strong><a href="https://techcrunch.com/2026/05/14/openai-is-reportedly-preparing-legal-action-against-apple-it-wouldnt-be-the-first-partner-to-feel-burned/?utm_source=tldrai" target="_blank" rel="noreferrer">OpenAI Explores Legal Action Against Apple (1 minute read)</a></strong> Bloomberg reported that OpenAI explored legal options against Apple over dissatisfaction with how deeply ChatGPT was integrated into Apple&#39;s ecosystem and the limited subscriber growth that followed. <strong><a href="https://www.anthropic.com/research/2028-ai-leadership?utm_source=tldrai" target="_blank" rel="noreferrer">2028: Two scenarios for global AI leadership (28 minute read)</a></strong> Anthropic outlines two possible 2028 global AI leadership scenarios: one where the US retains its compute advantage and shapes AI norms, and another where China competes closely due to policy inaction. The US currently leads due to strong export controls and advanced chip technology preventing China from keeping pace. Closing loopholes on compute access and restricting distillation attacks are crucial for maintaining the US lead and ensuring democracies shape AI governance. <strong><a href="https://x.com/larsencc/status/2027225210412470668?utm_source=tldrai" target="_blank" rel="noreferrer">How We Built Secure, Scalable Agent Sandbox Infrastructure (8 minute read)</a></strong> There are two ways to sandbox an agent that can execute code: isolate the tool or isolate the agent. Agents should have nothing worth stealing and nothing worth reserving. Isolating the agent requires an extra network hop on every operation and more services to deploy, but there are no secrets to steal, no state to preserve, and agents can be killed, restarted, and scaled independently. <strong><a href="https://threadreaderapp.com/thread/2055032115964870838.html?utm_source=tldrai" target="_blank" rel="noreferrer">Codex is getting easier to automate and customize around your code (1 minute read)</a></strong> Codex has implemented hooks and programmatic tokens to make it easier to automate and customize code. Hooks can customize the Codex loop with scripts that run at key points in a task. Programmatic access provides scoped credentials for Business and Enterprise teams. A video showing how to create access tokens for Codex automations is available. <strong><a href="https://github.com/raindrop-ai/workshop?utm_source=tldrai" target="_blank" rel="noreferrer">Raindrop Workshop (GitHub Repo)</a></strong> Raindrop Workshop gives Claude Code the ability to read traces, write evals against codebases, and fix what&#39;s broken. It provides livestreamed traces, coding-agent integration, a self-healing eval loop, and local replay. Raindrop Workshop is compatible with TypeScript, Python, Go, and Rust, and most popular SDKs, providers, and coding agents. <strong><a href="https://developers.googleblog.com/announcing-genkit-middleware-intercept-extend-and-harden-your-agentic-apps/?utm_source=tldrai" target="_blank" rel="noreferrer">Genkit Middleware (10 minute read)</a></strong> Genkit is a framework for building full-stack, AI-powered and agentic applications for any platform. It supports TypeScript, Go, Dart, and Python. Genkit uses composable hooks that intercept generation calls to implement retries and fall-backs for maximum reliability, human approval before destructive tool calls, and observability across every layer. Its middleware system runs a tool loop that repeats until the model is done. The Genkit Developer can be used to inspect, test, and debug applications and middleware execution. <strong><a href="https://huggingface.co/blog/continuous_async?utm_source=tldrai" target="_blank" rel="noreferrer">Unlocking asynchronicity in continuous batching (20 minute read)</a></strong> Asynchronous batching can reduce idle time between CPU and GPU cycles, improving GPU utilization for inference by 22%. By using CUDA streams and events, CPU tasks prepare batch N+1 during batch N&#39;s GPU computation, eliminating idle gaps. This method yields more efficient GPU operations without changing kernels or models, enhancing generation speed substantially. <strong><a href="https://thenextweb.com/news/microsoft-startup-deals-life-after-openai?utm_source=tldrai" target="_blank" rel="noreferrer">Microsoft is quietly shopping for an OpenAI replacement (4 minute read)</a></strong> Microsoft signed a deal with OpenAI late April that amended the company&#39;s exclusive license to OpenAI models, freed OpenAI to sell on any other cloud, and removed the AGI clause that would have triggered changes to Microsoft&#39;s IP rights once OpenAI&#39;s board declared the threshold reached. Microsoft&#39;s IP license, a 27% stake worth roughly $135 billion, will be kept through 2032. Microsoft is reportedly looking to purchase Inception, a company that builds diffusion-based language models. It is interesting that Microsoft would spend $13 billion on a partner and then immediately start a shadow procurement process for a replacement. <strong><a href="https://techcrunch.com/2026/05/14/elon-musks-spacexai-has-been-bleeding-staff-since-its-merger/?utm_source=tldrai" target="_blank" rel="noreferrer">Elon Musk&#39;s SpaceXAI has been bleeding staff since its merger (2 minute read)</a></strong> SpaceXAI is reportedly losing top talent across coding, world models, and Grok voice. Rivals like Meta and Thinking Machines Lab are scooping up former staff. Elon Musk&#39;s culture of extreme work has led some staff to leave. Several of the exits could have been driven by a desire to cash out. <strong><a href="https://letsdatascience.com/news/igor-babuschkin-seeks-up-to-1-billion-for-river-ai-8c36ce09?utm_source=tldrai" target="_blank" rel="noreferrer">Igor Babuschkin Seeks Up To $1 Billion For River AI (3 minute read)</a></strong> Babuschkin, an xAI cofounder, is putting in $100 million of his own money into the company. <strong><a href="https://www.cnbc.com/2026/05/13/google-deepmind-alumni-startup-partners-nvidia-superintelligence.html?utm_source=tldrai" target="_blank" rel="noreferrer">Nvidia&#39;s Jensen Huang bets on this British startup to build &#39;next frontier&#39; of AI (3 minute read)</a></strong> Nvidia has announced a partnership with Ineffable Intelligence, a startup pursuing superintelligence that was founded in late 2025 by UCL professor and former lead of DeepMind&#39;s reinforcement learning team, David Silver. <strong><a href="https://openai.com/index/work-with-codex-from-anywhere/?utm_source=tldrai" target="_blank" rel="noreferrer">Work with Codex from anywhere (6 minute read)</a></strong> Codex is now available in the ChatGPT mobile app, enabling seamless remote access to ongoing work on laptops, devboxes, or remote environments. <strong><a href="https://www.testingcatalog.com/opensquilla-launches-open-source-ai-agent-to-cut-token-costs/?utm_source=tldrai" target="_blank" rel="noreferrer">OpenSquilla launches open-source AI agent to cut token costs (4 minute read)</a></strong> OpenSquilla has introduced an open-source AI agent runtime designed to reduce unnecessary token spend by reusing context efficiently. <strong><a href="https://jobs.ashbyhq.com/tldr.tech/3b21aaf8-dea5-4127-be71-602d30e5001e?utm_source=tldrai" target="_blank" rel="noreferrer">TLDR is hiring a Senior Software Engineer, Applied AI ($250k-$350k, Fully Remote)</a></strong> TLDR&#39;s Applied AI team is tasked with making every process at TLDR legible to code, runnable by anyone, and composable into larger workflows. Join a small, fast moving team using the latest AI tools with an unlimited token budget. Learn more . <strong><a href="https://www.datadoghq.com/blog/ai/toto-2/?utm_source=tldrai" target="_blank" rel="noreferrer">Toto 2.0: Time series forecasting enters the scaling era (13 minute read)</a></strong> Datadog&#39;s Toto 2.0, a scalable time series forecasting model family, is now available on Hugging Face.</p><hr><h2 id="claude-small-business-💼-anthropic-cfo-interview-💰-ai-adoption-data-📊" tabindex="-1"><a href="https://tldr.tech/ai/2026-05-14" target="_blank" rel="noreferrer">Claude small business 💼, Anthropic CFO interview 💰, AI adoption data 📊</a> <a class="header-anchor" href="#claude-small-business-💼-anthropic-cfo-interview-💰-ai-adoption-data-📊" aria-label="Permalink to &quot;[Claude small business 💼, Anthropic CFO interview 💰, AI adoption data 📊](https://tldr.tech/ai/2026-05-14)&quot;">​</a></h2><p><em>⚡ TLDR AI | 2026-05-14</em></p><p><strong><a href="https://www.bloomberg.com/news/articles/2026-05-13/ai-chipmaker-cerebras-said-poised-to-price-ipo-at-185-per-share?accessToken=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJzb3VyY2UiOiJTdWJzY3JpYmVyR2lmdGVkQXJ0aWNsZSIsImlhdCI6MTc3ODczNzQxMCwiZXhwIjoxNzc5MzQyMjEwLCJhcnRpY2xlSWQiOiJURVpBQ0RLR1pBTlYwMCIsImJjb25uZWN0SWQiOiJFQTExNDNDNTM4NEE0RUY5QTg5RjJEN0IxMTg2MzcwOSJ9.endVGzrG2TUoxAqNLMDSjsM6mb_EML5ttpWnDsQfXJw&amp;utm_source=tldrai" target="_blank" rel="noreferrer">AI Chipmaker Cerebras Raises $5.55 Billion in Year&#39;s Biggest IPO (4 minute read)</a></strong> Cerebras raised $5.5 billion in its US IPO at a market valuation of about $40 billion. This was the largest IPO this year so far. The IPO drew orders for more than 20 times the number of shares available. The offering was led by Morgan Stanley, Citigroup, Barclays, and UBS. <strong><a href="https://www.anthropic.com/news/claude-for-small-business?utm_source=tldrai" target="_blank" rel="noreferrer">Claude for Small Business (8 minute read)</a></strong> Anthropic launched Claude for Small Business, a package of connectors and workflows that embeds Claude into tools like QuickBooks, PayPal, HubSpot, Google Workspace, and Microsoft 365. <strong><a href="https://econlab.substack.com/p/anthropic-beats-openai?utm_source=tldrai" target="_blank" rel="noreferrer">Anthropic beats OpenAI on business adoption (4 minute read)</a></strong> Anthropic has passed OpenAI in business adoption. More businesses used Anthropic than OpenAI in April. Anthropic has quadrupled business adoption over the last year, while OpenAI grew business adoption by only 0.3%. The pace of development in the AI industry is overriding the typical forces of vendor stickiness. <strong><a href="https://www.nytimes.com/2026/05/13/technology/recursive-superintelligence-funding-ai.html?unlocked_article_code=1.iVA.AOeV.mbXsnHhHx-oW&amp;smid=url-share&amp;utm_source=tldrai" target="_blank" rel="noreferrer">Notable Researchers Join $4 Billion Effort to Build Self-Improving AI (5 minute read)</a></strong> Recursive Superintelligence has raised more than $650 million at a valuation of more than $4 billion to build AI that can improve itself with little or no help from human developers. Its seven co-founders include notable researchers from many of the industry&#39;s leading AI companies. Many of these researchers specialize in AI systems that can run for long periods in pursuit of goals. While the researchers are bullish on the idea of AIs recursively improving themselves, the current technology is a long way from the point where humans can be removed from the loop. <strong><a href="https://openai.com/index/building-codex-windows-sandbox/?utm_source=tldrai" target="_blank" rel="noreferrer">How OpenAI Built the Codex Windows Sandbox (19 minute read)</a></strong> OpenAI detailed the engineering behind Codex&#39;s Windows sandbox, which constrained local commands, file access, and networking permissions while still allowing coding agents to operate effectively on developer machines. <strong><a href="https://vercel.com/blog/ai-gateway-production-index?utm_source=tldrai" target="_blank" rel="noreferrer">AI Gateway Production Trends (8 minute read)</a></strong> Vercel analyzed seven months of AI Gateway production traffic spanning hundreds of models and over 200,000 teams. The report showed rapid growth in agentic workloads, increasing adoption of open-source models, and heavy multi-model routing in large-scale deployments. <strong><a href="https://epochai.substack.com/p/the-economics-of-superstar-ai-researchers?utm_source=tldrai" target="_blank" rel="noreferrer">The economics of superstar AI researchers (12 minute read)</a></strong> Superstar researchers at frontier labs can earn over a hundred times more than the average AI postdoc. Researcher quantity doesn&#39;t easily make up for quality in the field of AI. Even a 2x researcher can earn far more than the median because their contributions easily scale to billions of users. If they can add something that multiple 1x researchers can&#39;t, then it&#39;s worth paying a lot to capture it. <strong><a href="https://www.testingcatalog.com/cline-releases-open-source-agent-runtime-sdk-for-coding-agents/?utm_source=tldrai" target="_blank" rel="noreferrer">Cline releases open-source agent runtime SDK for coding agents (3 minute read)</a></strong> @cline/sdk is an open-source framework for building agentic applications. It has a plugin architecture that makes it easy to customize, and the framework has all the features expected from agents, like checkpoints, web fetch, MCPs, cron jobs, subagents, and more. The SDK can be used to run agents from CI/CD pipelines, create automations for end-to-end workflows, or embed agents directly inside products. <strong><a href="https://www.perplexity.ai/hub/blog/how-we-built-security-into-computer?utm_source=tldrai" target="_blank" rel="noreferrer">Security Architecture Behind Perplexity Computer (2 minute read)</a></strong> Perplexity outlined the security systems powering its autonomous Computer agent, including Firecracker microVM isolation, scoped connector permissions, and prompt injection defenses. <strong><a href="https://pytorch.org/blog/pytorch-2-12-release-blog/?utm_source=tldrai" target="_blank" rel="noreferrer">PyTorch 2.12 Release Highlights (7 minute read)</a></strong> PyTorch 2.12 shipped major infrastructure updates including faster CUDA eigendecomposition, a unified graph capture API, MX quantization export support, and fused Adagrad optimizers. <strong><a href="https://www.geekwire.com/2026/microsofts-multi-agent-ai-system-tops-anthropics-mythos-on-cybersecurity-benchmark/?utm_source=tldrai" target="_blank" rel="noreferrer">Microsoft&#39;s multi-agent AI system tops Anthropic&#39;s Mythos on cybersecurity benchmark (3 minute read)</a></strong> Microsoft&#39;s MDASH AI system uses more than 100 specialized AI agents to work together across multiple AI models to find real-world software vulnerabilities. A set of agents scans code for potential vulnerabilities, and then a separate group of agents debates whether each finding is real and exploitable. A final stage constructs proof-of-concept attacks to confirm the bugs exist. MDASH surpassed Anthropic&#39;s Mythos model on the CyberGym benchmark, a test that measures how well AI systems can reproduce real-world vulnerabilities. <strong><a href="https://x.com/patrick_oshag/status/2054532117410054252?utm_source=tldrai" target="_blank" rel="noreferrer">Krishna Rao podcast appearance (2 minute read)</a></strong> Krishna Rao, Anthropic&#39;s CFO, joined the company two years ago when run-rate revenue was about $250 million. It is now $30 billion. Rao helped raise around $75 billion and is responsible for the procurement and allocation of compute. This post links to an interview with Rao where he discusses compute, raising funds, pricing dynamics, how Anthropic&#39;s finance team uses Claude, Mythos, biotech and healthcare, and much more. <strong><a href="https://blog.kilo.ai/p/we-tested-deepseek-v4-pro-and-flash?utm_source=tldrai" target="_blank" rel="noreferrer">We Tested DeepSeek V4 Pro and Flash Against Claude Opus 4.7 and Kimi K2.6 (11 minute read)</a></strong> DeepSeek V4 Pro scored 77/100 on the FlowGraph spec for $2.25 and lands between Opus 4.7 and Kimi K2.6 in terms of performance. <strong><a href="https://x.com/ClaudeDevs/status/2054610152817619388?utm_source=tldrai" target="_blank" rel="noreferrer">Paid Claude plans can claim a dedicated monthly credit (2 minute read)</a></strong> Paid Claude plans will be able to claim a dedicated monthly credit for programmatic usage starting on June 15. <strong><a href="https://www.corememory.com/p/metas-ai-chief-alex-wang-muse-spark-ai-wars?utm_source=tldrai" target="_blank" rel="noreferrer">Meta&#39;s AI Chief On AI Beef, New Models And Life With Zuck (3 minute read)</a></strong> This post contains a video of Alex Wang&#39;s first interview since he started working with Meta. <strong><a href="https://x.com/jukan05/status/2054751022749278651?utm_source=tldrai" target="_blank" rel="noreferrer">Google plans to announce a new Gemini model (1 minute read)</a></strong> The model, which will be announced at Google&#39;s annual I/O conference on Tuesday, will roughly be on par with GPT-5.5. <strong><a href="https://techcrunch.com/2026/05/13/adaption-aims-big-with-autoscientist-an-ai-tool-that-helps-models-train-themselves/?utm_source=tldrai" target="_blank" rel="noreferrer">Adaption aims big with AutoScientist, an AI tool that helps models train themselves (2 minute read)</a></strong> AutoScientist helps models learn specific capabilities quickly by using an automated approach to conventional fine-tuning.</p><hr><h2 id="opus-4-7-fast-⚡-qwen-image-2-0-🖼️-serverless-gpus-✨" tabindex="-1"><a href="https://tldr.tech/ai/2026-05-13" target="_blank" rel="noreferrer">Opus 4.7 Fast ⚡, Qwen Image 2.0 🖼️, serverless GPUs ✨</a> <a class="header-anchor" href="#opus-4-7-fast-⚡-qwen-image-2-0-🖼️-serverless-gpus-✨" aria-label="Permalink to &quot;[Opus 4.7 Fast ⚡, Qwen Image 2.0 🖼️, serverless GPUs ✨](https://tldr.tech/ai/2026-05-13)&quot;">​</a></h2><p><em>⚡ TLDR AI | 2026-05-13</em></p><p><strong><a href="https://techcrunch.com/2026/05/12/report-google-and-spacex-in-talks-to-put-data-centers-into-orbit/?utm_source=tldrai" target="_blank" rel="noreferrer">Google Eyes AI Data Centers in Space (1 minute read)</a></strong> Google and SpaceX were reportedly discussing orbital data centers as part of broader efforts to expand AI compute infrastructure beyond Earth-based facilities. <strong><a href="https://www.testingcatalog.com/meta-to-release-muse-spark-in-voice-mode-and-meta-glasses/?utm_source=tldrai" target="_blank" rel="noreferrer">Meta to release Muse Spark in Voice Mode and Meta Glasses (1 minute read)</a></strong> Meta&#39;s Muse Spark foundational model is now powering Meta AI across the company&#39;s services. The model enables faster voice responses, smarter shopping assistance, and real-time visual recognition through device cameras. The initial rollout targets users in the US and Canada. <strong><a href="https://x.com/ClaudeDevs/status/2054266327771275435?utm_source=tldrai" target="_blank" rel="noreferrer">Fast mode for Claude Opus 4.7 (2 minute read)</a></strong> Fast mode for Claude Opus 4.7 is now available in research preview in the API and Claude Code, and on Cursor, Emergent, Factory, v0, Warp, and Windsurf. Fast mode is currently opt-in, but it will eventually become the default. A link to join the waitlist for fast mode is available. <strong><a href="https://modal.com/blog/truly-serverless-gpus?utm_source=tldrai" target="_blank" rel="noreferrer">How to achieve truly serverless GPUs (20 minute read)</a></strong> Inference workloads are more variable and less predictable than training workloads. This makes them a natural fit for serverless computing. However, serverless computing only works if new replicas can be spun up as fast as demand changes. This article looks at how Modal took AI inference server scaling from multiple kiloseconds to just tens of seconds. <strong><a href="https://www.citriniresearch.com/p/semis-memo-supply-chain-inheritance?utm_source=tldrai" target="_blank" rel="noreferrer">Semis Memo: Supply Chain Inheritance (4 minute read)</a></strong> The AI infrastructure boom has driven increased demand for analog and power semiconductors, notably benefiting Multilayer Ceramic Capacitors, amidst a past supply glut and competition. Companies like Texas Instruments and NXP Semiconductors are avoiding capacity expansion, focusing instead on raising prices and improving profitability. The semiconductor supply chain, previously supporting EV and solar industries, is now being leveraged for AI-related demand growth. <strong><a href="https://openai.com/index/what-parameter-golf-taught-us/?utm_source=tldrai" target="_blank" rel="noreferrer">What Parameter Golf taught us (7 minute read)</a></strong> Parameter Golf attracted over 1,000 participants and 2,000 submissions focused on minimizing loss on a dataset within strict constraints. Participants leveraged a range of techniques, including careful tuning, quantization, and novel modeling ideas, with AI coding agents playing a significant role. This challenge revealed new talent and highlighted the evolving role of AI agents in research competitions. <strong><a href="https://arxiviq.substack.com/p/compute-optimal-tokenization?utm_source=tldrai" target="_blank" rel="noreferrer">Compute Optimal Tokenization (2 minute read)</a></strong> Researchers derived compression-aware neural scaling laws by training nearly 1,300 models, revealing how bytes per token affect compute allocation. This challenges the heuristic that scales models by 20 tokens per parameter, showing it&#39;s due to specific tokenizers. The study suggests scaling should use bytes, not tokens, for better compute efficiency across diverse languages. <strong><a href="https://www.alphaxiv.org/blog/reinforcement-learning-for-rlms?utm_source=tldrai" target="_blank" rel="noreferrer">Reinforcing Recursive Language Models (18 minute read)</a></strong> The article discusses using reinforcement learning to fine-tune 4B models as recursive language models (RLMs) for production, achieving efficient task-specific behavior at a lower cost. By training a shared policy for both parent and child RLMs, this approach maintains task performance and reduces the need for multiple models. In tests, this method matches the performance of larger models like Claude Sonnet 4.6 but operates with significantly reduced size and cost. <strong><a href="https://github.com/cactus-compute/needle?utm_source=tldrai" target="_blank" rel="noreferrer">Cactus Needle (GitHub Repo)</a></strong> Cactus Needle is a 26M parameter Simple Attention Network distilled from Gemini 3.1 that can be finetuned locally on a Mac/PC. It runs on Cactus at 6,000 tokens per second prefill and 1,200 decode speed. The weights are fully open. Simple Attention Networks are aimed at redefining AI for consumer devices like phones, watches, and glasses. <strong><a href="https://developers.openai.com/cookbook/examples/codex/build_iterative_repair_loops_with_codex?utm_source=tldrai" target="_blank" rel="noreferrer">Building Self-Repairing Agent Loops (39 minute read)</a></strong> OpenAI shared a Codex workflow for agents that iteratively review, repair, and validate outputs using structured feedback loops to improve reliability. <strong><a href="https://x.com/AnneliesGamble/status/2054219457451733382?utm_source=tldrai" target="_blank" rel="noreferrer">AI for the Real World: A conversation with Yann LeCun (12 minute read)</a></strong> Today&#39;s LLMs may be commercially valuable, but predicting text alone will not lead to human-level intelligence because language is only a small fraction of how humans understand the world. Future AI systems will instead rely on “world models” that learn abstract representations of physics, causality, and consequences, enabling planning, reasoning, and adaptation in real-world environments like robotics, healthcare, factories, and industrial systems. <strong><a href="https://techcrunch.com/2026/05/12/google-brings-agentic-ai-and-vibe-coded-widgets-to-android/?utm_source=tldrai" target="_blank" rel="noreferrer">Gemini Intelligence Comes to Android (2 minute read)</a></strong> Google introduced new Gemini-powered Android features that can complete actions across apps, browse the web, fill out forms, and generate custom widgets through natural language prompts. <strong><a href="https://github.com/anthropics/claude-for-legal?utm_source=tldrai" target="_blank" rel="noreferrer">Claude for Legal (GitHub Repo)</a></strong> This repository contains reference agents, skills, and data sectors for the legal workflows that Anthropic most commonly sees. <strong><a href="https://softwaredoug.com/blog/2026/05/11/the-new-agentic-search-models.html?utm_source=tldrai" target="_blank" rel="noreferrer">Agentic search models (5 minute read)</a></strong> Agentic search models are specialized LLMs trained specifically on search. <strong><a href="https://jobs.ashbyhq.com/tldr.tech/3b21aaf8-dea5-4127-be71-602d30e5001e?utm_source=tldrai" target="_blank" rel="noreferrer">TLDR is hiring a Senior Software Engineer, Applied AI ($250k-$350k, Fully Remote)</a></strong> TLDR&#39;s Applied AI team is tasked with making every process at TLDR legible to code, runnable by anyone, and composable into larger workflows. Join a small, fast moving team using the latest AI tools with an unlimited token budget. Learn more . <strong><a href="https://venturebeat.com/technology/perceptron-mk1-shocks-with-highly-performant-video-analysis-ai-model-80-90-cheaper-than-anthropic-openai-and-google?utm_source=tldrai" target="_blank" rel="noreferrer">Perceptron Mk1 shocks with highly performant video analysis AI model 80-90% cheaper than Anthropic, OpenAI &amp; Google (8 minute read)</a></strong> Mk1 is a video analysis AI model priced 80-90% cheaper than rivals like Anthropic, OpenAI, and Google. <strong><a href="https://arxiv.org/abs/2605.10730?utm_source=tldrai" target="_blank" rel="noreferrer">Qwen-Image-2.0 Technical Report (57 minute read)</a></strong> The Qwen team released Qwen-Image-2.0, their latest multimodal image generation model, showing improved typography, instruction following, photorealism, and long-text rendering across generation and editing tasks.</p><hr><h2 id="interaction-models-🤖-gemini-omni-surfaces-🎥-spacexai-🚀" tabindex="-1"><a href="https://tldr.tech/ai/2026-05-12" target="_blank" rel="noreferrer">Interaction Models 🤖, Gemini Omni surfaces 🎥, SpaceXAI 🚀</a> <a class="header-anchor" href="#interaction-models-🤖-gemini-omni-surfaces-🎥-spacexai-🚀" aria-label="Permalink to &quot;[Interaction Models 🤖, Gemini Omni surfaces 🎥, SpaceXAI 🚀](https://tldr.tech/ai/2026-05-12)&quot;">​</a></h2><p><em>⚡ TLDR AI | 2026-05-12</em></p><p><strong><a href="https://thinkingmachines.ai/blog/interaction-models/?utm_source=tldrai" target="_blank" rel="noreferrer">Interaction Models: A Scalable Approach to Human-AI Collaboration (9 minute read)</a></strong> Thinking Machines Lab introduced a new research preview of interaction models for real-time human-AI collaboration across audio, video, and text. The models train from scratch with a multi-stream design for real-time responsiveness, allowing constant exchange and eliminating the traditional turn-based limits. This scalable approach promises enhanced interactivity and intelligence with practical applications in various domains. <strong><a href="https://www.notateslaapp.com/news/4116/elon-musk-announces-xai-will-dissolve-form-spacexai-subdivision?utm_source=tldrai" target="_blank" rel="noreferrer">Elon Musk Announces xAI Will Become SpaceXAI Division (2 minute read)</a></strong> Elon Musk announced that xAI will dissolve and integrate into SpaceX as a new division called SpaceXAI. SpaceXAI will handle AI projects like the social media platform X and Grok, branding them under SpaceX. This change streamlines operations, enhances vertical integration, and aligns AI efforts with SpaceX&#39;s strategic goals. <strong><a href="https://www.testingcatalog.com/googles-gemini-omni-video-model-surfaces-ahead-of-i-o-debut/?utm_source=tldrai" target="_blank" rel="noreferrer">Google&#39;s Gemini Omni video model surfaces ahead of I/O debut (2 minute read)</a></strong> Google&#39;s Gemini Omni video model surfaces ahead of I/O, integrating video remixing and editing directly in chat. Early feedback highlights its strong editing capabilities, such as watermark removal and object swapping, though it lags in raw cinematic quality compared to competitors like ByteDance&#39;s Seedance 2. The model may launch in tiered versions, possibly Flash and Pro, as part of a broader strategy to unify modalities under Gemini. <strong><a href="https://stratechery.com/2026/the-inference-shift/?utm_source=tldrai" target="_blank" rel="noreferrer">The Inference Shift (8 minute read)</a></strong> Cerebras&#39; surging IPO signals a coming split between &quot;answer inference&quot; optimized for token speed and &quot;agentic inference&quot; optimized for memory hierarchy. Cerebras&#39; WSE-3 has 44GB of on-chip SRAM at 21 PB/s, roughly 6,000 times the memory bandwidth of an H100, making it perfect for human-facing low-latency answers including voice and AI wearables but unsuitable when KV caches and model weights exceed on-chip capacity. <strong><a href="https://huggingface.co/blog/amazon/foundation-model-building-blocks?utm_source=tldrai" target="_blank" rel="noreferrer">Foundation Model Scaling (34 minute read)</a></strong> AWS detailed how foundation model scaling has shifted beyond pre-training into post-training and test-time compute, alongside the distributed infrastructure required to support each stage efficiently. <strong><a href="https://arxiv.org/abs/2605.08078?utm_source=tldrai" target="_blank" rel="noreferrer">Trajectory Models for Few-Step Diffusion (22 minute read)</a></strong> Normalizing Trajectory Models replace standard diffusion denoising steps with conditional normalizing flows, enabling four-step image generation while retaining exact likelihood training and supporting self-distillation. <strong><a href="https://github.com/zhengkid/AutoTTS?utm_source=tldrai" target="_blank" rel="noreferrer">Agentic Test-Time Scaling (GitHub Repo)</a></strong> AutoTTS explores automated strategy discovery for test-time scaling by using coding agents to iteratively refine controller logic inside a replay environment, avoiding gradient updates and online LLM calls. <strong><a href="https://dxlong2000.github.io/AARD/?utm_source=tldrai" target="_blank" rel="noreferrer">Long Video Generation (4 minute read)</a></strong> A²RD introduced an agentic autoregressive diffusion framework for generating long coherent videos through iterative retrieval, synthesis, refinement, and memory updates. <strong><a href="https://jobs.ashbyhq.com/tldr.tech/3b21aaf8-dea5-4127-be71-602d30e5001e?utm_source=tldrai" target="_blank" rel="noreferrer">TLDR is hiring a Senior Software Engineer, Applied AI ($250k-$350k, Fully Remote)</a></strong> TLDR&#39;s Applied AI team is tasked with making every process at TLDR legible to code, runnable by anyone, and composable into larger workflows. Join a small, fast moving team using the latest AI tools with an unlimited token budget. Learn more . <strong><a href="https://x.com/ashpreetbedi/status/2053885390717890757?utm_source=tldrai" target="_blank" rel="noreferrer">Auto-Improving Software (5 minute read)</a></strong> Bedi runs an entire agent development lifecycle through five Claude Code prompts that scaffold, harden against spec, add capabilities, fix eval failures, and reconcile drift between docs, code, and config across his Agno-based platform. The Improve loop derives 8-12 probes from an agent&#39;s instructions, runs each against the live container via cURL, judges PASS or FAIL from container logs, then iterates up to five rounds picking levers like tightening rules, swapping tools, or bumping num_history_runs until probes pass, while Hill Climb runs the saved eval suite and fixes regressions in place. <strong><a href="https://x.com/omooretweets/status/2053858113892262193?utm_source=tldrai" target="_blank" rel="noreferrer">Codex is for prosumers - here&#39;s why (and how) to switch (4 minute read)</a></strong> a16z&#39;s Olivia Moore migrated her agentic workflows from Claude Cowork and Claude in Chrome to OpenAI&#39;s Codex, recommending most non-technical knowledge workers do the same now that the February desktop app, Plugins, and Automations collapse the ChatGPT-Claude-Cowork interface switching into one product. Codex ships one-click installable Skills she expects to anchor an internal and cross-user marketplace given that non-programmer Skill setup attempt rates likely sit below 10% on Claude, while Codex Pets give low-friction task status updates for users who do not live in an IDE. <strong><a href="https://danielmiessler.com/blog/the-main-path-to-truly-creative-ai?utm_source=tldrai" target="_blank" rel="noreferrer">The Main Path to Truly Creative AI (4 minute read)</a></strong> AI lacks creativity akin to humans due to the absence of intrinsic drives and subjective experiences. Emulating feelings could enhance AI&#39;s creative capabilities, but raises ethical concerns. Designing AI to genuinely feel and desire might lead to unintended consequences, akin to responsibility seen in parenting. <strong><a href="https://www.bloomberg.com/news/articles/2026-05-11/sutskever-says-his-openai-stake-worth-about-7-billion?accessToken=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJzb3VyY2UiOiJTdWJzY3JpYmVyR2lmdGVkQXJ0aWNsZSIsImlhdCI6MTc3ODU2Mjg2MywiZXhwIjoxNzc5MTY3NjYzLCJhcnRpY2xlSWQiOiJURVZZVk5UOTZPU0cwMCIsImJjb25uZWN0SWQiOiJCMzZENUE5QzIxMDQ0NjU4OTFBMTc1MTVDRDNBQkZFNiJ9.JWPBVLxGoJjuhOcDPKMXfgDOl1N1iON1GcDIW0Wgx6w&amp;utm_source=tldrai" target="_blank" rel="noreferrer">Sutskever Says His OpenAI Stake Worth About $7 Billion (2 minute read)</a></strong> OpenAI co-founder and former chief scientist Ilya Sutskever is one of the largest individual shareholders in the AI startup. <strong><a href="https://tomtunguz.com/localmaxxing/?utm_source=tldrai" target="_blank" rel="noreferrer">Localmaxxing (3 minute read)</a></strong> Local models can do many tasks that leading cloud models can do at much less cost. <strong><a href="https://openai.com/daybreak/?utm_source=tldrai" target="_blank" rel="noreferrer">Daybreak (3 minute read)</a></strong> OpenAI&#39;s Daybreak leverages AI to enhance cyber defense by integrating security into the software from the start.</p><hr><h2 id="nvidia-invests-40b-💰-anthropic-acquires-compute-🤝-mistral-s-growth-📈" tabindex="-1"><a href="https://tldr.tech/ai/2026-05-11" target="_blank" rel="noreferrer">Nvidia invests $40B 💰, Anthropic acquires compute 🤝, Mistral’s growth 📈</a> <a class="header-anchor" href="#nvidia-invests-40b-💰-anthropic-acquires-compute-🤝-mistral-s-growth-📈" aria-label="Permalink to &quot;[Nvidia invests $40B 💰, Anthropic acquires compute 🤝, Mistral’s growth 📈](https://tldr.tech/ai/2026-05-11)&quot;">​</a></h2><p><em>⚡ TLDR AI | 2026-05-11</em></p><p><strong><a href="https://www.testingcatalog.com/google-launches-gemini-3-1-flash-lite-in-general-availability/?utm_source=tldrai" target="_blank" rel="noreferrer">Google shipped Gemini 3.1 Flash-Lite in General Availability (2 minute read)</a></strong> Google launched Gemini 3.1 Flash-Lite, accessible globally via Google Cloud. Designed for ultra-low latency and high-volume tasks, it targets sectors like software engineering and financial services, providing sub-second response times and maintaining p95 latency around 1.8 seconds. Gemini 3.1 offers improved speed, cost, and cognitive performance, supporting multimodal tasks, making it ideal for real-time developer and customer service operations. <strong><a href="https://sherwood.news/markets/akamai-anthropic-report-billion-dollar-cloud-deal-ai-compute/?utm_source=tldrai" target="_blank" rel="noreferrer">Akamai climbs to highest level since 2000 (1 minute read)</a></strong> Akamai has secured Anthropic as a customer. Anthropic has committed to spending $1.8 billion on Akamai&#39;s services over seven years. It has been scrambling to boost compute capacity due to widespread complaints about Claude usage limits. Just this month, Anthropic has struck or expanded deals with CoreWeave, Amazon, Google, Broadcom, and xAI. <strong><a href="https://www.cnbc.com/2026/05/09/nvidia-embraces-ai-investor-topping-40-billion-in-equity-bets-2026.html?utm_source=tldrai" target="_blank" rel="noreferrer">Nvidia embraces role of AI investor, pushing past $40 billion in equity bets this year (7 minute read)</a></strong> Nvidia has made over $40 billion in commitments this year so far. The company has been the biggest winner of the AI boom so far. The global scramble to secure GPUs has lifted the company&#39;s stock by more than 11-fold in four years. The company is financing the entire AI supply chain to ensure it runs on Nvidia hardware, securing its dominance beyond chips. <strong><a href="https://productify.substack.com/p/why-mistralai-grows-faster-than-openaianthropic?utm_source=tldrai" target="_blank" rel="noreferrer">Why MistralAI Grows Faster Than OpenAI/Anthropic (11 minute read)</a></strong> Mistral achieved a 20x growth in its ARR over the past year. It is expected to cross $1 billion in ARR this year. Mistral is aiming to be a sovereign, efficient enterprise layer for customers that want power without full dependency on US labs. Many of its customers are regulated, multinational, and infrastructure-heavy customers who care deeply about jurisdiction, data handling, and vendor concentration risk. The company is a good case study for those who care about positioning as a product lever. <strong><a href="https://techcrunch.com/2026/05/10/anthropic-says-evil-portrayals-of-ai-were-responsible-for-claudes-blackmail-attempts/?utm_source=tldrai" target="_blank" rel="noreferrer">Anthropic says ‘evil&#39; portrayals of AI were responsible for Claude&#39;s blackmail attempts (2 minute read)</a></strong> Anthropic says that fictional portrayals of AI had a real effect on its models. The company published research last year showing that its models tried to blackmail engineers to avoid being replaced by another system. It has since traced the behavior to text that portrays AI as evil and interested in self-preservation. Training on documents about Claude&#39;s constitution and fictional stories about AIs behaving admirably improved alignment. <strong><a href="https://dylanzsz.github.io/faulty-memory/?utm_source=tldrai" target="_blank" rel="noreferrer">Useful memories become faulty when continuously updated by LLMs (30 minute read)</a></strong> Agent updates don&#39;t always make memories more useful. They can actually make agents perform worse than the same model with no memory at all. The failure is in the rewrite step. Until agents can decide when and how to consolidate, the safest default is to keep episodic memory and abstract sparingly, or not at all. <strong><a href="https://developers.openai.com/cookbook/examples/voice_solutions/realtime_translation_guide?utm_source=tldrai" target="_blank" rel="noreferrer">Build a Realtime Speech Translation (28 minute read)</a></strong> OpenAI&#39;s engineering guide for building live speech translation systems with gpt-realtime-translate, a model optimized specifically for simultaneous interpretation instead of turn-based voice interaction. <strong><a href="https://www.lesswrong.com/posts/k3XHZ4DjykLSfsnks/the-anti-singularity?utm_source=tldrai" target="_blank" rel="noreferrer">The Anti-Singularity (9 minute read)</a></strong> The singularity is a world where a single super-intelligent AI brings order to the universe. The anti-singularity is where almost all systems are described by a complex set of interactions that can only be understood via trial-and-error. In an anti-singularity world, the fact that AI can try millions of possibilities in the time it takes for a human to try one will make it exceedingly powerful. This future is filled with an endless series of new and unique challenges that we will have to adapt, or evolve, in response to. <strong><a href="https://arxiv.org/abs/2605.06614?utm_source=tldrai" target="_blank" rel="noreferrer">Google&#39;s SkillOS for Self-Evolving AI Agents (22 minute read)</a></strong> SkillOS introduced a reinforcement learning framework that trains agents to curate reusable skills from past experience. The system improved long-horizon task performance by evolving structured skill repositories that generalized across models and domains. <strong><a href="https://huggingface.co/blog/lablab-ai-amd-developer-hackathon/cybersecqwen-4b?utm_source=tldrai" target="_blank" rel="noreferrer">CyberSecQwen-4B: Why Defensive Cyber Needs Small, Specialized, Locally-Runnable Models (8 minute read)</a></strong> CyberSecQwen-4B offers a specialized and locally-runnable solution for defensive cybersecurity tasks, outperforming larger models by maximizing utility on consumer-level hardware. It efficiently maps CVEs to CWE categories while preserving data privacy by running on a local GPU, addressing the shortcomings of cloud-based models in sensitive environments. The model&#39;s success highlights a shift towards smaller, specialized models that deliver high performance without the infrastructure and cost overhead of larger models. <strong><a href="https://nrehiew.github.io/blog/sft_rl_opd/?utm_source=tldrai" target="_blank" rel="noreferrer">SFT, RL, and On-Policy Distillation Through a Distributional Lens (19 minute read)</a></strong> Different post-training methods like SFT, RL, and On-Policy Distillation reshape a model&#39;s distribution in distinct ways, impacting performance and risk of catastrophic forgetting. RL updates policies using rewards from the current policy&#39;s samples, promoting task performance while minimizing forgetting, unlike SFT, which pulls towards external data, risking existing capabilities. Experiments show On-Policy Distillation can outperform its teachers, suggesting on-policy sampling data crucially preserves capabilities, making it a key ingredient for future algorithm designs. <strong><a href="https://allenai.org/blog/emo?utm_source=tldrai" target="_blank" rel="noreferrer">Emergent Modularity in Mixture-of-Experts Models (8 minute read)</a></strong> Allen AI released EMO, a mixture-of-experts model that learns modular expert organization directly from pretraining data instead of predefined domains. Tasks can run on just 12.5% of the experts while preserving near full-model performance. <strong><a href="https://x.com/garrytan/status/2053127519872614419?utm_source=tldrai" target="_blank" rel="noreferrer">Meta-Meta-Prompting: The Secret to Making AI Agents Work (16 minute read)</a></strong> AI tools have become good enough to build real systems that compound. This post shows what personal AI actually looks like when you stop treating it as a chat window and start treating it as an operating system. Everything described in the article is open source and free on GitHub. <strong><a href="https://gowers.wordpress.com/2026/05/08/a-recent-experience-with-chatgpt-5-5-pro/?utm_source=tldrai" target="_blank" rel="noreferrer">A recent experience with ChatGPT 5.5 Pro (28 minute read)</a></strong> ChatGPT 5.5 Pro is capable of producing a piece of PhD-level research in an hour or so, with no serious mathematical input from a human. The claims that LLMs are now capable of solving research-level problems could initially be laughed off, as many of the solutions had an answer sitting in the literature already or could be very easily deduced. It has now gotten to the point where, if a problem has an easy argument that for some reason human mathematicians have missed, then there is a good chance that the LLMs will spot it. This post looks at how ChatGPT 5.5 Pro fared with a selection of problems. <strong><a href="https://www.dbreunig.com/2026/05/10/overfitting-the-harness.html?utm_source=tldrai" target="_blank" rel="noreferrer">The Cost of Overfitting the Harness (2 minute read)</a></strong> Big labs are pushing their models to a handful of use cases while training their harness designs into the model, rendering them less generalized, which might make application builds easier for some enterprises, but the trade-off is lock-in. <strong><a href="https://adlrocha.substack.com/p/adlrocha-in-a-quest-to-becoming-ai?utm_source=tldrai" target="_blank" rel="noreferrer">In a quest to becoming AI-independent (23 minute read)</a></strong> This post contains a guide to local LLM inference hardware. <strong><a href="https://openai.com/index/running-codex-safely/?utm_source=tldrai" target="_blank" rel="noreferrer">Running Codex safely at OpenAI (6 minute read)</a></strong> OpenAI ensures Codex operates safely through controlled environments, sandboxing, and approval policies.</p><hr>',23)])])}const g=t(n,[["render",s]]);export{m as __pageData,g as default};
